class Solution:
    def leastOpsExpressTarget(self, x: int, target: int) -> int:
        if target == 1:
            return 0
        if target == x:
            return 1
        ops = [float('inf')] * (target + 1)
        ops[1] = 1
        for i in range(2, target + 1):
            for j in range(1, min(i, x) + 1):
                if i % j == 0:
                    ops[i] = min(ops[i], ops[i // j] + 1)
        return ops[target]
```

